VALUES
  ('optometrist-moex-00214', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列何者不是造成硬式透氧隱形眼鏡（RGPlens）曲折（flexure）的常見原因？', '["較陡中心基弧驗配", "鏡片中心厚度太薄", "中央光學區直徑（opticzonediameter,OZD）較小", "低透氧率（Dk）鏡片材質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00215', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '若矯正鏡架視力良好的患者戴上硬式鏡片，插片驗光後視力品質還是不佳，下列原因何者錯誤？', '["表面潤濕性差，如果是新的鏡片、可能沒有充分潤濕", "光學扭曲（opticaldistorsion）出現在鏡片表面上會干擾視力", "表面沉積物或刮傷", "黃斑部中心凹裂孔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00216', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一位16歲學生戴眼鏡已多年，沒有戴過隱形眼鏡。有過敏性結膜炎，經常揉眼睛。最近覺得右眼視力模糊，想 要配新眼鏡，右眼插片驗光，以-3.75DS/-1.75DC×162，最佳矯正視力為0.8；左眼以-2.00DS/-0.75DC×006可 矯正至 1.0。角膜弧度儀顯示右眼 44.12@165：46.00@75（反射環 mire 稍微扭曲），左眼 43.25@180：', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00217', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '25@90（反射環mire正常）。角膜地形圖顯示右眼角膜最陡峭之處在中心下方約1-2mm處為49.00D。 細隙燈評估右眼角膜有Vogt’s細紋。下列敘述何者錯誤？', '["可配戴硬式隱形眼鏡來矯正右眼視力", "可能是圓錐角膜病變", "右眼可能是角膜變形（cornealwarpagesyndrome）", "角膜弧度儀顯示左眼為順性散光"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00218', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜地形圖的圖形，下列敘述何者錯誤？', '["差異圖（differencemap）可用來比較角膜塑型片戴用以後角膜前後的差異", "高度圖（elevationmap）較能完整表現出角膜的形狀", "軸向圖（axialmap）可以顯示出真正的角膜頂點（cornealapex）", "矢狀圖（sagittalmap）上每一個點的弧度，都是經過視軸所計算出來，又稱軸向圖（axialmap）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00219', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '乾眼是戴軟式隱形眼鏡後的常見併發症，下列何者原因最不相關？', '["配戴者的淚水質量不佳", "因配戴鏡片導致淚水層變厚", "吃口服避孕藥", "長時間使用電腦"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00220', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一名 25 歲男性，一週前戴著軟式隱形眼鏡在溪中游泳，今天早上右眼突然感覺強烈疼痛、結膜紅腫、怕 光及視力模糊，裂隙燈檢查發現右眼基質層圓形浸潤（stromalring-shapeinfiltrate），最可能的診斷為：', '["綠膿桿菌（Pseudomonasaeruginosa）感染的細菌性角膜炎", "單純性皰疹（Herpessimplex）感染的病毒性角膜炎", "白色念珠菌（Candidaalbicans）感染的黴菌性角膜炎", "棘狀阿米巴（Acanthamoeba）角膜炎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00221', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於隱形眼鏡誘發上角膜輪部角結膜炎（superiorlimbickeratoconjunctivitis）的原因，下列何者錯誤？', '["與慢性葡萄球菌感染有關", "與防腐劑硫柳汞（thimerosal）過敏有關", "與長期角膜缺氧有關", "可能為鏡片後表面機械性摩擦結膜造成的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00222', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關隱形眼鏡相關之內皮細胞水腫（contact-lens-associatedendothelialbedewing,CLEB）之敘述，下列何者 錯誤？', '["經常發生於雙眼", "以背面反射照射法觀察時，可看到CLEB呈現細小白色沉澱物狀", "會造成視力模糊", "可能會與角膜上皮水腫（epithelialedema）一起發生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00223', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關單眼視覺法老花隱形眼鏡的驗配，下列敘述何者錯誤？', '["驗配方法簡單", "適合散光度數較高者", "老花度數愈高，成功率愈低", "適合有明顯弱視者（視力小於6/12）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
